import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styles: [`
    :host {
      --primary: #4f46e5;
      --primary-hover: #4338ca;
      --dark: #111827;
      --text-main: #374151;
      --text-light: #6b7280;
      --bg-subtle: #f9fafb;
    }

    .auth-wrapper {
      min-height: 100vh;
      display: flex;
